"    function updateGlobeRotation() {
        // 1. Update dot positions & visibility using the cached data
        for (let i = 0; i < dotElementsAndData.length; i++) {
            const item = dotElementsAndData[i];
            const el = item.el;
            const dot = item.dot;

            const cosLat = Math.cos(dot.lat);
            const sinLat = Math.sin(dot.lat);
            const cosLon = Math.cos(dot.lon);
            const sinLon = Math.sin(dot.lon);

            const x0 = cosLat * sinLon;
            const y0 = sinLat;
            const z0 = cosLat * cosLon;

            // X-axis rotation (tilt)
            const y1 = y0 * Math.cos(rotX) - z0 * Math.sin(rotX);
            const z1 = y0 * Math.sin(rotX) + z0 * Math.cos(rotX);

            // Y-axis rotation (spin)
            const x2 = x0 * Math.cos(rotY) + z1 * Math.sin(rotY);
            const z2 = -x0 * Math.sin(rotY) + z1 * Math.cos(rotY);

            if (z2 >= 0) {
                const px = cx + R * x2;
                const py = cy - R * y1;
                el.setAttribute('cx', px.toFixed(1));
                el.setAttribute('cy', py.toFixed(1));
                el.style.display = 'block';

                // Real 3D depth-scaling
                const depthFactor = 0.35 + 0.65 * z2;
                el.setAttribute('r', (dot.isLand ? 1.35 * depthFactor : 0.7 * depthFactor).toFixed(1));
                el.style.opacity = (dot.isLand ? 0.95 * z2 : 0.35 * z2).toFixed(1);
            } else {
                el.style.display = 'none';
            }
        }"

